-- Phase 2: Workflows Service Independent Database Schema\n-- Database: postgres-workflows:5439\n\nCREATE TABLE IF NOT EXISTS workflows (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    user_id UUID NOT NULL,\n    name VARCHAR(255),\n    status VARCHAR(20),\n    created_at TIMESTAMP DEFAULT NOW()\n);\n\nCREATE TABLE IF NOT EXISTS workflow_steps (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    workflow_id UUID NOT NULL REFERENCES workflows(id) ON DELETE CASCADE,\n    step_number INT,\n    action VARCHAR(255),\n    created_at TIMESTAMP DEFAULT NOW()\n);\n\nCREATE TABLE IF NOT EXISTS workflow_executions (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    workflow_id UUID NOT NULL REFERENCES workflows(id) ON DELETE CASCADE,\n    status VARCHAR(20),\n    started_at TIMESTAMP,\n    completed_at TIMESTAMP,\n    created_at TIMESTAMP DEFAULT NOW()\n);\n\nCREATE INDEX idx_workflows_user_id ON workflows(user_id);\nCREATE INDEX idx_workflow_steps_workflow_id ON workflow_steps(workflow_id);\nCREATE INDEX idx_workflow_executions_workflow_id ON workflow_executions(workflow_id);\n\nGRANT USAGE ON SCHEMA public TO workflows_user;\nGRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA public TO workflows_user;\nGRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO workflows_user;\n"